ntenance of good hygiene practices\"], \"precautions\": [\"avoiding excessive moisture\", \"monitoring for secondary infections\"], \"disease_name\": \"Late Blight\", \"affected_areas\": [\"leaf\", \"stem\", \"fruit\"], \"disease_progression\": \"The disease spreads to the rest of the foliage, leading to extensive defoliation, and can infect tomato seed and other above-ground parts of the plant.\", \"recommended_actions\": [\"immediately removing infected plants to prevent further spread\", \"applying fungicides to prevent infection of healthy plants\"]}','{\"shelf_life\": \"1-3 weeks\", \"storage_type\": \"cold room\", \"humidity_range\": \"85-95%\", \"temperature_range\": \"0-2°C or 18-21°C\", \"storage_conditions\": \"separate from pears and other ethylene sensitive products, avoid citrus treated with biphenyl\", \"post_harvest_handling\": \"cooling, sorting\", \"expected_spoilage_time\": \"3-7 days\"}','{\"dosage\": \"100-200 kg per hectare\", \"npk_ratio\": \"5:10:10\", \"micronutrients\": \"Zinc, Boron, Iron\", \"application_method\": \"broadcast or drip fertigation\", \"application_timing\": \"basal at sowing and top dressing at flowering stage\", \"recommended_fertilizer\": \"NPK 5-10-10\"}','{\"harvest_method\": \"manual\", \"harvest_duration\": \"65-100 days\", \"best_harvest_time\": \"early morning\", \"equipment_required\": [\"pruning shears\", \"gloves\"], \"harvest_indicators\": [\"fruit color\", \"fruit softening\"], \"yield_considerations\": \"cultivar, maturity level, ripeness, and growth period\", \"expected_harvest_date\": \"between 50-65 days for early varieties and 85-95 days for late varieties\"}','{\"current\": {\"rain_mm\": 0.0, \"condition\": \"Light Drizzle\", \"feels_like_c\": 42.9, \"temperature_c\": 42.0, \"wind_speed_kmh\": 12.1, \"humidity_percent\": 23, \"precipitation_mm\": 0.1, \"wind_direction_deg\": 265, \"cloud_cover_percent\": 36}, \"latitude\": 28.6139, \"timezone\": \"Asia/Kolkata\", \"longitude\": 77.209, \"fetched_at\": \"20