-- Table structure for table `disease_awareness`
--

DROP TABLE IF EXISTS `disease_awareness`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `disease_awareness` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `disease_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `affected_crops` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` longtext COLLATE utf8mb4_unicode_ci,
  `symptoms` longtext COLLATE utf8mb4_unicode_ci,
  `prevention` longtext COLLATE utf8mb4_unicode_ci,
  `treatment` longtext COLLATE utf8mb4_unicode_ci,
  `image_url` varchar(1000) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `severity_level` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'low, medium, high, critical',
  `source_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source_url` varchar(1000) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT '1',
  `is_alert` tinyint(1) DEFAULT '0' COMMENT 'Shows in feed disease alert section',
  `content_hash` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `published_at` datetime DEFAULT NULL,
  `synced_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `priority` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'medium',
  `severity_score` float DEFAULT '5',
  `recommended_action` longtext COLLATE utf8mb4_unicode_ci,
  `related_schemes` json DEFAULT NULL,
  `language` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT 'en',
  PRIMARY KEY (`id`),
  UNIQUE KEY `content_hash` (`content_hash`),
  KEY `idx_da_is_alert` (`is_alert`),
  KEY `idx_da_severity` (`severity_level`),
  KEY `idx_da_is_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `disease_awareness`
