LOCK TABLES `disease_awareness` WRITE;
/*!40000 ALTER TABLE `disease_awareness` DISABLE KEYS */;
INSERT INTO `disease_awareness` VALUES (7,'Wheat Rust','Wheat','A fungal disease that affects wheat stems and leaves.','Reddish-brown powdery pustules on leaves and stems.','Use resistant varieties and crop rotation.','Apply appropriate fungicides when early symptoms appear.','https://th-i.thgim.com/public/incoming/4dte8f/article71058472.ece/alternates/LANDSCAPE_1200/2026-05-26T111406Z_1846173829_RC2A8LAEAD89_RTRMADP_3_IRAQ-AGRICULTURE-WHEAT.JPG','high','Plant Health Institute',NULL,1,1,'bdd2842f36894306092a8ff6da5fd51c706780cf5d7596b67df48e8679dc05c1',NULL,'2026-06-12 06:23:48','2026-06-12 06:23:48','critical',8.5,'Immediate fungicide application is required to prevent 80% yield loss.','[{\"link\": \"https://pmfby.gov.in/\", \"name\": \"PM Fasal Bima Yojana\"}]','en');
/*!40000 ALTER TABLE `disease_awareness` ENABLE KEYS */;
UNLOCK TABLES;

