INSERT INTO `soil_health_awareness` VALUES (11,'Summer Deep Ploughing','soil_preparation','Deep ploughing exposes soil-borne pests and weed seeds to harsh sunlight.','Deep ploughing in summer months helps in eradication of weeds, pests, and improves soil structure for the upcoming Kharif season.','https://upload.wikimedia.org/wikipedia/commons/6/6d/Ploughing_with_tractor.jpg','Soil Health Card Portal','https://soilhealth.dac.gov.in/',1,0,'2bc6049d7276ec0e6611530d9bbe8c73c8ee59a731fc46e00a70d11d6d90f1b8','2026-06-12 12:51:45','2026-06-12 07:21:44','2026-06-12 07:21:44','en'),(12,'Green Manuring','soil_fertility','Grow dhaincha or sunhemp before main crop to boost organic matter.','Incorporating green manure crops like Sesbania adds up to 60-80 kg N/ha and improves soil aeration and water holding capacity.','https://upload.wikimedia.org/wikipedia/commons/e/e0/Sesbania_bispinosa.jpg','Soil Health Card Portal','https://soilhealth.dac.gov.in/',1,0,'253e9b2c436a25f72c61d18c8f35c53a2ae4a044c499cad69d7c5b8e9bd9375d','2026-06-12 12:51:45','2026-06-12 07:21:44','2026-06-12 07:21:44','en'),(13,'Soil pH Management','soil_ph','Test soil pH and apply lime or gypsum accordingly.','Acidic soils require liming (agricultural lime), while alkaline soils require gypsum application. Get a soil test done before sowing.','https://upload.wikimedia.org/wikipedia/commons/6/64/Soil_testing_kit.jpg','Soil Health Card Portal','https://soilhealth.dac.gov.in/',1,0,'0c9a0adb56d0b540fa8a5482b01c78c533c71a90327eafb30013004bea85ae4b','2026-06-12 12:51:45','2026-06-12 07:21:44','2026-06-12 07:21:44','en');
/*!40000 ALTER TABLE `soil_health_awareness` ENABLE KEYS */;
UNLOCK TABLES;

