INSERT INTO `weather_awareness` VALUES (7,'Heavy Rainfall Warning','monsoon','Heavy to very heavy rainfall expected in the coming 48 hours.','Potential waterlogging in low-lying fields. High risk of soil erosion.','Ensure proper drainage in fields. Delay fertilizer application until rain stops.','Northern Plains','Meteorological Department',NULL,1,1,'05e4841354fea23c835d0acedc419427f696135c6f12c6b0686ca16b477f3548',NULL,'2026-06-12 06:23:48','2026-06-12 06:23:48','high',9,'severe','Move harvested crops to dry storage and clear field drainage channels immediately.','[{\"link\": \"https://pmfby.gov.in/\", \"name\": \"PM Fasal Bima Yojana\"}]','en'),(8,'Weather Update: Northern Plains','general','Current Temperature: 30.4°C, Expected Precipitation: 9.9mm','Normal weather conditions. Ideal for regular farming activities.','Continue with scheduled irrigation and fertilizer application.','Northern Plains','Open-Meteo / IMD','https://open-meteo.com',1,0,'1ef80137d26bf875ea7e007757fa6586eb0379a6045b176f9729758cb8c19093','2026-06-12 12:42:40','2026-06-12 07:12:45','2026-06-12 07:12:45','medium',5,'medium',NULL,NULL,'en'),(9,'Weather Update: Central India','general','Current Temperature: 37.3°C, Expected Precipitation: 1.1mm','Normal weather conditions. Ideal for regular farming activities.','Continue with scheduled irrigation and fertilizer application.','Central India','Open-Meteo / IMD','https://open-meteo.com',1,0,'2341f490aea80308e6af20585811a35e89d09f13d082b7b1b84d901042232178','2026-06-12 12:42:42','2026-06-12 07:12:45','2026-06-12 07:12:45','medium',5,'medium',NULL,NULL,'en'),(10,'Weather Update: Western India','general','Current Temperature: 33.6°C, Expected Precipitation: 2.5mm','Normal weather conditions. Ideal for regular farming activities.','Continue with scheduled irrigation and fertilizer application.','Western India','Open-Meteo / IMD','https://open-meteo.com',1,0,'01468863d45fee59db336e2526c0b5941704d376fd1bc5b1a8830b5475cce885','2026-06-12 12:42:44','2026-06-12 07:12:45','2026-06-12 07:12:45','medium',5,'medium',NULL,NULL,'en'),(11,'Weather Update: Southern Peninsula','general','Current Temperature: 33.0°C, Expected Precipitation: 2.9mm','Normal weather conditions. Ideal for regular farming activities.','Continue with scheduled irrigation and fertilizer application.','Southern Peninsula','Open-Meteo / IMD','https://open-meteo.com',1,0,'97474ec33657c28d8875d34050276ebac2bb5b336327cc8c423364c32eab89a9','2026-06-12 12:42:45','2026-06-12 07:12:45','2026-06-12 07:12:45','medium',5,'medium',NULL,NULL,'en');
